import re
from pathlib import Path

# Check all router files for unused imports
router_dir = Path("/Users/zhouboli/Documents/maimai-assistant/src/web/routers")
for router_file in sorted(router_dir.glob("*.py")):
    if router_file.name == "__init__.py":
        continue

    content = router_file.read_text()
    lines = content.split('\n')

    # Extract all imports
    imports = {}
    for i, line in enumerate(lines):
        match = re.search(r'from .* import (.+)', line)
        if match:
            imports_list = [x.strip() for x in match.group(1).split(',')]
            for imp in imports_list:
                if ' as ' in imp:
                    imp = imp.split(' as ')[-1].strip()
                imports[imp] = i + 1

    # Check usage for each import
    unused = []
    for imp, line_num in imports.items():
        usage_count = 0
        for i, line in enumerate(lines):
            if i + 1 != line_num:  # Not the import line
                if re.search(rf'\b{imp}\b(?!\s*=\s*)', line):
                    usage_count += 1

        if usage_count == 0:
            unused.append((imp, line_num))

    if unused:
        print(f"\n{router_file.name}:")
        for imp, line_num in unused:
            print(f"  Line {line_num}: {imp}")
